// This function attempts to keep backwards compatibility with type prop

import includes from '@andes/common/build/utils/includes';

/** @typedef {Pick<import('../..').SnackbarProps, 'color'>} ComputeColorProp */
/** @typedef {'negative' | 'positive' } ComputeColorResult */

/** @type {(props: ComputeColorProp) => ComputeColorResult | undefined} */
const computeTypeColor = ({ color }) => {
  if (includes(['red', 'negative'], color || '')) return 'negative';
  if (includes(['green', 'positive'], color || '')) return 'positive';

  return undefined;
};

export default computeTypeColor;
