/* eslint-disable no-undef */
import React, { useEffect } from 'react';

import Snackbar from '../Snackbar';

// @ts-ignore
const SnackbarWebkit = (props) => {
  const [error, setError] = React.useState(false);
  const {
    show = false,
    message,
    action,
    delay,
    onChange,
    onOpen,
    onClose,
    color,
  } = props;

  function getColor() {
    let realColor = 'basic';

    if (color === 'green' || color === 'positive') {
      realColor = 'positive';
    } else if (color === 'red' || color === 'negative') {
      realColor = 'negative';
    }

    return realColor;
  }

  async function onOpenSnackbar() {
    // Webkit expects duration in seconds
    const durationInSeconds = delay / 1000;

    const options = {
      message,
      duration: durationInSeconds,
      action: action?.text,
      onDismiss: typeof onClose === 'function',
      color: getColor(),
    };

    // @ts-ignore
    function getEventName(name, id) {
      return `nordic:${name}${id ? `:${id}` : ''}`;
    }

    // @ts-ignore
    const { id } = await MobileWebKit.executeNative({
      method: 'wk:snackbar-show',
      args: options,
    });

    const dismissEvent = getEventName('onSnackbarDismiss', id);

    // @ts-ignore
    MobileWebKit.on(dismissEvent, () => {
      if (typeof onClose === 'function') {
        onClose();
        if (typeof onChange === 'function') onChange(false);
      }
      // @ts-ignore
      MobileWebKit.off(dismissEvent);
    });

    if (typeof onOpen === 'function') {
      onOpen();
      if (typeof onChange === 'function') onChange(true);
    }
  }

  useEffect(() => {
    if (show && !error) {
      onOpenSnackbar().catch(() => { setError(true); });
    }
  }, [show, error]);

  if (show && error) {
    return <Snackbar {...props} />;
  }

  return null;
};

export default SnackbarWebkit;
