/* eslint-disable react/sort-comp */
import React from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { VisuallyHidden } from '@andes/visually-hidden';
import { DEPRECATED_COLOR_WARNINGS } from './constants/warnings';
import { AVAILABLE_COLOR, DEPRECATED_COLOR, namespace } from './constants';
import computeTypeColor from './utils/computeTypeColor';
import includes from '@andes/common/build/utils/includes';
import warning from '@andes/common/build/utils/warning';

/** @typedef {import('..').ActionConfigType} ActionConfig */

/**
 * @typedef SnackbarState
 * @prop {boolean} display
 * @prop {boolean} show
 * @prop {boolean} prevShow
 * @prop {boolean} srLabelVisibility
 * @prop {boolean} timeoutExecuted
 */

/** @typedef {import('..').SnackbarProps} SnackbarPublicProps */

/**
 * @typedef {Object} InternalProps
 * @prop {React.Ref<HTMLDivElement>} [innerRef]
 * @prop {React.ReactNode} [children]
 * @prop {{ root?: string }} [classNames]
 * @prop {Record<string, unknown>} [andesDataAttributes]
 */

/** @typedef {SnackbarPublicProps & InternalProps} SnackbarProps */

/** @extends React.Component<SnackbarProps, SnackbarState> */
class Snackbar extends React.Component {
  /** @param {SnackbarProps} props */
  constructor(props) {
    super(props);

    const { show = false } = this.props;

    this.onActionClick = this.onActionClick.bind(this);
    this.onAnimationEnd = this.onAnimationEnd.bind(this);
    this.setMainContainerRef = this.setMainContainerRef.bind(this);
    /** @type {SnackbarState} */
    this.state = {
      display: show,
      show,
      prevShow: show,
      timeoutExecuted: false,
      srLabelVisibility: false,
    };

    this.style = {};
  }

  componentDidMount() {
    const {
      show = false,
      color,
      delay,
      onOpen,
    } = this.props;

    // @deprecate [color] - Warning from: 9.0.0
    if (typeof color === 'string') {
      warning(
        !includes(DEPRECATED_COLOR, color),
        DEPRECATED_COLOR_WARNINGS[/** @type {keyof DEPRECATED_COLOR_WARNINGS} */ (color)],
      );
    }

    const fixedElement = /** @type {HTMLElement} */ (document.querySelector('.andes-snackbar-fixed-element'));

    if (fixedElement) {
      this.style = {
        bottom: `${fixedElement.offsetHeight + 16}px`,
      };
    }

    if (show && delay) {
      this.delayTimeout = setTimeout(() => {
        this.setState({
          show: false,
        }, () => {
          if (this.isReduceMotion()) this.onClose();
        });
      }, delay);
    }

    this.labelTimeout = setTimeout(() => {
      this.setState({
        srLabelVisibility: true,
      });
    }, 30);

    if (show && typeof onOpen === 'function') {
      onOpen();
    }
  }

  componentWillUnmount() {
    clearTimeout(this.delayTimeout);
    clearTimeout(this.labelTimeout);
  }

  /**
   * @param {SnackbarState} prevState
   * @param {SnackbarProps} nextProps
   */
  static getDerivedStateFromProps(nextProps, prevState) {
    const { show = false } = nextProps;
    const { show: stateShow, timeoutExecuted, prevShow } = prevState;
    const showChangedProp = show !== prevShow;

    if (showChangedProp) {
      if (show && !timeoutExecuted) {
        return {
          display: true,
          show,
          prevShow: show,
        };
      }

      if (show !== stateShow && !timeoutExecuted) {
        return {
          show: show || false,
          prevShow: show,
        };
      }

      if (timeoutExecuted) {
        return {
          timeoutExecuted: false,
          prevShow: show,
        };
      }
    }

    return null;
  }

  /**
   * @param {SnackbarProps} _
   * @param {SnackbarState} prevState
   */
  componentDidUpdate(_, prevState) {
    const { show: stateShow } = this.state;
    const { show: prevStateShow } = prevState;
    const { onOpen, show = false, delay } = this.props;

    const startedShowing = !prevStateShow && stateShow;
    const hasDelayProps = delay;

    if (stateShow !== prevStateShow) {
      if (show && onOpen) onOpen();
      if (this.isReduceMotion() && !show) this.onClose();
    }

    if (startedShowing && hasDelayProps) {
      this.delayTimeout = setTimeout(() => {
        this.setState({
          show: false,
          timeoutExecuted: true,
        }, () => {
          if (this.isReduceMotion()) this.onClose();
        });
      }, delay);
    }
  }

  /**
   * @param {React.SyntheticEvent<HTMLAnchorElement | HTMLButtonElement>} event
   * @param {ActionConfig['onClick']} [onClickProp]
   */
  onActionClick(event, onClickProp) {
    if (typeof onClickProp === 'function') {
      clearTimeout(this.delayTimeout);
      onClickProp(event);
    }
  }

  onClose() {
    const { onClose } = this.props;
    clearTimeout(this.delayTimeout);
    if (typeof onClose === 'function') onClose();
  }

  onAnimationEnd() {
    const { show } = this.state;
    if (!show) {
      this.onClose();
      this.setState({ display: false });
    }
  }

  isReduceMotion() {
    return typeof window !== 'undefined'
    && window?.matchMedia('(prefers-reduced-motion: reduce)').matches === true;
  }

  /** @param {HTMLDivElement} ref */
  setMainContainerRef(ref) {
    const { innerRef } = this.props;

    if (innerRef) {
      if (typeof innerRef === 'function') {
        innerRef(ref);
      } else {
        innerRef.current = ref;
      }
    }
  }

  /**
   * @typedef {Object} Props
   * @prop {ActionConfig['text']} [text]
   * @prop {ActionConfig['onClick']} [onClick]
   */
  /** @param {Props} props */
  renderAction({ text, onClick }) {
    const common = {
      'data-andes-snackbar-action': true,
      className: `${namespace}__action`,
      onClick: /** @type {ActionConfig['onClick']} */ ((event) => this.onActionClick(event, onClick)),
    };

    return text && (
      <button {...common}>
        {text}
      </button>
    );
  }

  render() {
    const {
      action,
      className,
      color,
      children,
      message,
      classNames: classes,
      andesDataAttributes,
    } = this.props;
    const { display, show, srLabelVisibility } = this.state;

    const computedAction = action || {};
    const computedColor = computeTypeColor({ color });

    const containerClassNames = classNames(namespace, className, `${namespace}--${computedAction.position || 'right'}`, {
      [`${namespace}--${computedColor}`]: computedColor,
      [`${namespace}--with-action`]: computedAction || children,
      [`${namespace}--animate-show`]: show,
      [`${namespace}--animate-hide`]: show === false,
    }, classes?.root);

    const isReduced = this.isReduceMotion();

    if (!display || show === null || (isReduced && show === false)) {
      return null;
    }

    return (
      <div
        className={containerClassNames}
        onAnimationEnd={this.onAnimationEnd}
        role="presentation"
        ref={this.setMainContainerRef}
        style={this.style}
        data-andes-snackbar
        data-andes-snackbar-color={color}
        {...andesDataAttributes}
      >
        <div>
          <VisuallyHidden role="alert" aria-live="assertive">
            {srLabelVisibility && message}
          </VisuallyHidden>
          <p className={`${namespace}__message`} data-andes-snackbar-message>{message}</p>
          {children && (
            <div className={`${namespace}__children`} data-andes-snackbar-content>
              {children}
            </div>
          )}
        </div>
        {this.renderAction(computedAction)}
      </div>
    );
  }
}

Snackbar.displayName = 'Snackbar';

Snackbar.propTypes = {
  action: PropTypes.shape({
    text: PropTypes.string.isRequired,
    onClick: PropTypes.func,
    position: PropTypes.oneOf(['right', 'bottom']),
  }),
  className: PropTypes.string,
  color: PropTypes.oneOf(AVAILABLE_COLOR),
  children: PropTypes.node,
  delay: PropTypes.number,
  innerRef: PropTypes.shape({
    current: PropTypes.oneOfType([PropTypes.node, PropTypes.object]),
  }),
  message: PropTypes.string.isRequired,
  onClose: PropTypes.func,
  onOpen: PropTypes.func,
  show: PropTypes.bool,
  classNames: PropTypes.shape({}),
  andesDataAttributes: PropTypes.shape({}),
};

export default Snackbar;
