import React from 'react';
import { isWebkit2 } from '@andes/common/build/webkit/utils';

import SnackbarWebkit from './SnackbarWebkit';
import Snackbar from '../Snackbar';

/**
 * @typedef {Object} SnackbarContainerInternalProps
 * @prop {Record<string, unknown>} [andesDataAttributes]
 */

/** @typedef {import('../..').SnackbarProps} SnackbarContainerPublicProps */

/** @type {React.FunctionComponent<SnackbarContainerPublicProps & SnackbarContainerInternalProps>} */
const SnackbarContainer = ({ ref, ...props }) => {
  if (isWebkit2()
    // @ts-expect-error - children is not a prop of SnackbarProps
    && !props?.children
    && !ref
    && !props?.action?.onClick
    && props.delay
  ) {
    return (
      <SnackbarWebkit {...props} />
    );
  }

  return (
    <Snackbar
      innerRef={ref}
      {...props}
    />
  );
};

SnackbarContainer.displayName = 'Snackbar';

export default SnackbarContainer;
